import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"모드 설치","description":"Fabric용 모드를 설치하는 방법에 대한 단계적 가이드입니다.","frontmatter":{"title":"모드 설치","description":"Fabric용 모드를 설치하는 방법에 대한 단계적 가이드입니다.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.4/players/installing-mods.md","filePath":"versions/1.21.4/translated/ko_kr/players/installing-mods.md","lastUpdated":1760721669000}`);var s={name:`ko_kr/1.21.4/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">모드 설치 <a class="header-anchor" href="#h1" aria-label="Permalink to “모드 설치”">​</a></h1><p>이 가이드에서는 공식 Minecraft 런처의 Fabric에 모드를 설치하는 방법을 알려줄 것입니다.</p><p>제3자 런처의 경우, 해당 런처의 문서를 참조하여 주세요.</p><h2 id="1-download-the-mod" tabindex="-1">1. 모드 다운로드 <a class="header-anchor" href="#1-download-the-mod" aria-label="Permalink to “1. 모드 다운로드”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>항상 신뢰할 수 있는 출처에서 모드를 다운로드해야 합니다. <a href="./finding-mods">안전한 모드 찾기</a>에서 더 많은 정보를 알아볼 수 있습니다.</p></div><p>대부분의 모드는 Fabric API를 필요로 하며, <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a>와 <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>에서 공식 모드를 다운로드할 수 있습니다.</p><p>모드를 다운로드할 때, 아래 사항을 확인하여 주세요:</p><ul><li>플레이하고자 하는 Minecraft 버전이 지원되는지 확인해야 합니다. 예를 들어, 버전 1.20을 지원하는 모드는 1.20.2에서 작동하지 않을 수 있습니다.</li><li>모드 로더가 Fabric인지 확인해야 합니다.</li><li>더욱이, 해당 모드가 Minecraft: &quot;Java Edition&quot;용인지 확인해야 합니다.</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. 다운로드한 모드를 <code>mods</code> 폴더로 옮기기 <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. 다운로드한 모드를 mods 폴더로 옮기기”">​</a></h2><p><code>mods</code> 폴더는 운영 체제에 따라 다음과 같은 위치에서 찾을 수 있습니다:</p><p>(파일 탐색기/Finder의 주소 표시줄에 아래 주소를 복사하여 붙여넣으면 빠르게 폴더로 이동할 수 있습니다)</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p><code>mods</code> 폴더를 찾으셨다면, 다운로드한 모드 <code>.jar</code> 파일을 폴더에 이동하면 됩니다.</p><p><img src="/assets/players/installing-mods.png" alt="Mods 폴더에 모드가 설치된 모습" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. 이제 끝났습니다! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. 이제 끝났습니다!”">​</a></h2><p><code>mods</code> 폴더에 모드를 이동했다면, Minecraft 런처를 실행하고 왼쪽 아래의 버전 선택에서 Fabric을 선택하고 플레이를 클릭하면 됩니다.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Fabric 프로필이 선택된 Minecraft 런처" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">문제 해결 <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “문제 해결”">​</a></h2><p>설치 과정 중 문제가 발생했다면, <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord (영어)</a>의 <code>#player-support</code> 채널에서 도움을 요청할 수 있습니다.</p><p>스스로 문제 해결 페이지를 읽고 직접 문제를 해결할 수도 있습니다:</p><ul><li><a href="./troubleshooting/crash-reports">충돌 보고서</a></li><li><a href="./troubleshooting/uploading-logs">로그 업로드</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};